struct ConfigPath {
    source: String,
    target: String,
}

fn process_configs(configs: Vec<ConfigPath>) -> io::Result<()> {
    let total = configs.len();
    println!("Starting configuration linking for {} items...", total);

    for (index, config) in configs.into_iter().enumerate() {
        let current = index + 1;
        print!("Processing item {}/{}... r", current, total);
        io::stdout().flush()?;
        std::thread::sleep(std::time::Duration::from_millis(50));
    }

    println!("nSuccessfully linked all configurations.");
    Ok(())
}

