use std::io::{self, Write};

struct ProgressBar {
    total: u64,
    current: u64,
    width: usize,
}

impl ProgressBar {
    fn new(total: u64) -> Self {
        ProgressBar { total, current: 0, width: 50 }
    }

    fn set_status(&mut self, step: u64) {
        self.current = step.min(self.total);
        let fraction = self.current as f64 / self.total as f64;
        let filled_width = (fraction * self.width as f64).round() as usize;

        print!("[={: <width$}] {:.2}% ({}/{})", 
            std::iter::repeat('#').take(filled_width).collect::<String>(), 
            &format!("{:.1}", fraction * 100.0), 
            self.current, 
            self.total, 
            width = self.width);
        io::stdout().flush().unwrap();
    }
}

fn main() {
    let mut bar = ProgressBar::new(200);

    for i in 1..=5 { 
        bar.set_status(i * 40); 
        std::thread::sleep(std::time::Duration::from_millis(300));
    }

    bar.set_status(200);
    println!("nTask complete!");
}
